<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            user-select: none;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            overflow: hidden;
            height: 100vh;
            width: 100vw;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, #2e3440 0%, #3b4252 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 48px;
            background-color: rgba(31, 35, 42, 0.9);
            backdrop-filter: blur(10px);
            display: flex;
            align-items: center;
            padding: 0 16px;
            z-index: 1000;
        }

        .launcher {
            width: 48px;
            height: 48px;
            margin-right: 12px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.2s;
        }

        .launcher:hover {
            background-color: rgba(255, 255, 255, 0.1);
            transform: scale(1.05);
        }

        .launcher-icon {
            width: 32px;
            height: 32px;
            fill: #fff;
        }

        /* Windows */
        .window {
            position: absolute;
            background-color: rgba(46, 52, 64, 0.98);
            border-radius: 12px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            overflow: hidden;
            display: none;
            min-width: 360px;
            min-height: 240px;
            border: 1px solid rgba(255, 255, 255, 0.1);
        }

        .window.active {
            display: flex;
            flex-direction: column;
        }

        /* Window Header */
        .win-header {
            height: 36px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 12px;
            cursor: default;
        }

        .win-title {
            color: white;
            font-size: 14px;
            font-weight: 500;
        }

        .win-controls {
            display: flex;
            gap: 8px;
        }

        .win-close {
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background-color: #bf616a;
            cursor: pointer;
            transition: transform 0.2s;
        }

        .win-close:hover {
            transform: scale(1.1);
        }

        /* Files Window */
        #files-window {
            top: 80px;
            left: 100px;
            width: 640px;
            height: 480px;
        }

        .files-path-bar {
            padding: 12px;
            background-color: rgba(255, 255, 255, 0.05);
            border-bottom: 1px solid rgba(255, 255, 255, 0.1);
        }

        .files-path {
            color: #88c0d0;
            font-size: 14px;
            display: flex;
            align-items: center;
        }

        .path-segment {
            margin-right: 8px;
            cursor: pointer;
        }

        .path-separator {
            color: #d8dee9;
            margin-right: 8px;
        }

        .files-up-btn {
            background-color: rgba(255, 255, 255, 0.1);
            border: none;
            border-radius: 4px;
            padding: 6px 12px;
            color: white;
            cursor: pointer;
            font-size: 13px;
            margin-left: auto;
        }

        .files-up-btn:hover {
            background-color: rgba(255, 255, 255, 0.2);
        }

        .files-content {
            flex: 1;
            padding: 16px;
            overflow-y: auto;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 16px;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 12px;
            border-radius: 8px;
            cursor: pointer;
            transition: background-color 0.2s;
        }

        .fs-item:hover {
            background-color: rgba(255, 255, 255, 0.1);
        }

        .fs-icon {
            width: 48px;
            height: 48px;
            margin-bottom: 8px;
            fill: #d8dee9;
        }

        .fs-name {
            font-size: 13px;
            text-align: center;
            color: white;
            word-break: break-word;
        }

        /* Notepad Window */
        #notepad-window {
            top: 60px;
            left: 200px;
            width: 720px;
            height: 540px;
        }

        .tabs-container {
            display: flex;
            background-color: #3b4252;
            border-bottom: 1px solid rgba(255, 255, 255, 0.1);
        }

        .tab-strip {
            display: flex;
            overflow-x: auto;
            flex: 1;
        }

        .tab {
            padding: 8px 16px;
            background-color: #4c566a;
            color: white;
            border-right: 1px solid rgba(255, 255, 255, 0.1);
            cursor: pointer;
            min-width: 100px;
            position: relative;
        }

        .tab.active {
            background-color: #434c5e;
            border-top: 2px solid #88c0d0;
        }

        .tab-close {
            position: absolute;
            right: 6px;
            top: 50%;
            transform: translateY(-50%);
            width: 16px;
            height: 16px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 12px;
            color: white;
        }

        .tab-close:hover {
            background-color: rgba(255, 255, 255, 0.2);
        }

        #new-tab-btn {
            padding: 8px 16px;
            background-color: #4c566a;
            color: white;
            border-left: 1px solid rgba(255, 255, 255, 0.1);
            cursor: pointer;
        }

        #new-tab-btn:hover {
            background-color: #5e667b;
        }

        .editor-container {
            flex: 1;
            position: relative;
        }

        #editor {
            width: 100%;
            height: 100%;
            background-color: #2e3440;
            color: #d8dee9;
            border: none;
            padding: 16px;
            font-family: monospace;
            font-size: 14px;
            line-height: 1.5;
            resize: none;
            outline: none;
        }

        /* Scrollbar styling */
        ::-webkit-scrollbar {
            width: 8px;
            height: 8px;
        }

        ::-webkit-scrollbar-track {
            background: rgba(255, 255, 255, 0.1);
        }

        ::-webkit-scrollbar-thumb {
            background: #4c566a;
            border-radius: 4px;
        }

        ::-webkit-scrollbar-thumb:hover {
            background: #5e667b;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div class="launcher" id="open-files" title="Files">
                <svg class="launcher-icon" viewBox="0 0 24 24">
                    <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
                </svg>
            </div>
            <div class="launcher" id="open-notepad" title="Text Editor">
                <svg class="launcher-icon" viewBox="0 0 24 24">
                    <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>
                </svg>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window">
            <div class="win-header">
                <span class="win-title">Files</span>
                <div class="win-controls">
                    <div class="win-close"></div>
                </div>
            </div>

            <div class="files-path-bar">
                <div class="files-path" id="files-path">
                    <!-- Path segments will be added here -->
                </div>
                <button id="files-up">Up</button>
            </div>

            <div class="files-content" id="files-listing">
                <!-- File/folder items will be added here -->
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window">
            <div class="win-header">
                <span class="win-title">Text Editor</span>
                <div class="win-controls">
                    <div class="win-close"></div>
                </div>
            </div>

            <div class="tabs-container">
                <div class="tab-strip" id="tabs">
                    <!-- Tabs will be added here -->
                </div>
                <button id="new-tab">+ New</button>
            </div>

            <div class="editor-container">
                <textarea id="editor"></textarea>
            </div>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            '/': ['bin', 'etc', 'home', 'usr', 'var'],
            '/bin': ['bash', 'cat', 'cp', 'ls'],
            '/etc': ['config', 'hosts', 'passwd'],
            '/home': ['user'],
            '/home/user': ['Documents', 'Downloads', 'Pictures', 'notes.txt'],
            '/home/user/Documents': ['report.docx', 'resume.pdf'],
            '/home/user/Downloads': ['software.iso', 'updates.zip'],
            '/home/user/Pictures': ['wallpaper.png', 'screenshot.jpg'],
            '/usr': ['bin', 'lib', 'share'],
            '/var': ['log', 'www', 'cache']
        };

        // Files window state
        let currentPath = '/';
        const filesWindow = document.getElementById('files-window');
        const filesPathElement = document.getElementById('files-path');
        const filesListingElement = document.getElementById('files-listing');
        const filesUpButton = document.getElementById('files-up');

        // Notepad state
        let tabs = [];
        let activeTabId = null;
        const notepadWindow = document.getElementById('notepad-window');
        const tabStripElement = document.getElementById('tabs');
        const newTabButton = document.getElementById('new-tab');
        const editorElement = document.getElementById('editor');

        // Initialize files window
        function renderFilesPath() {
            const segments = currentPath.split('/').filter(segment => segment);

            let html = '<span class="path-separator">/</span>';
            if (segments.length === 0) {
                html += '<span class="path-segment" data-path="/">root</span>';
            } else {
                let pathSoFar = '';
                segments.forEach((segment, index) => {
                    pathSoFar += '/' + segment;
                    const isLast = index === segments.length - 1;
                    if (isLast) {
                        html += `<span class="path-segment" data-path="${pathSoFar}">${segment}</span>`;
                    } else {
                        html += `<span class="path-segment" data-path="${pathSoFar}">${segment}</span><span class="path-separator">/</span>`;
                    }
                });
            }

            filesPathElement.innerHTML = html;
        }

        function renderFilesListing() {
            // Clear current listing
            filesListingElement.innerHTML = '';

            // Get directory contents
            const items = fileSystem[currentPath] || [];

            // Create folder and file icons
            items.forEach(item => {
                const isFolder = (fileSystem[currentPath + item] !== undefined);

                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';
                itemDiv.dataset.path = currentPath + item;
                itemDiv.dataset.name = item;
                itemDiv.innerHTML = `
                    <svg class="fs-icon" viewBox="0 0 24 24">
                        ${isFolder 
                            ? '<path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>' 
                            : '<path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>'}
                    </svg>
                    <div class="fs-name">${item}</div>
                `;

                // Double-click to navigate into folder
                itemDiv.addEventListener('dblclick', () => {
                    if (isFolder) {
                        currentPath = currentPath + item + '/';
                        renderFiles();
                    }
                });

                filesListingElement.appendChild(itemDiv);
            });
        }

        function renderFiles() {
            renderFilesPath();
            renderFilesListing();
        }

        // Files window event listeners
        filesUpButton.addEventListener('click', () => {
            if (currentPath !== '/') {
                const pathParts = currentPath.split('/').filter(p => p);
                if (pathParts.length > 0) {
                    pathParts.pop();
                    currentPath = '/' + pathParts.join('/') + '/';
                    renderFiles();
                } else {
                    currentPath = '/';
                    renderFiles();
                }
            }
        });

        filesPathElement.addEventListener('click', (e) => {
            const target = e.target.closest('.path-segment');
            if (target) {
                currentPath = target.dataset.path;
                renderFiles();
            }
        });

        // Notepad functionality
        function generateTabId() {
            return 'tab-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
        }

        function createNewTab() {
            const tabId = generateTabId();
            const newTab = {
                id: tabId,
                title: `Untitled ${tabs.length + 1}`,
                content: ''
            };

            tabs.push(newTab);
            activeTabId = tabId;

            renderTabs();
            loadActiveTabContent();
            saveNotepadState();
        }

        function renderTabs() {
            // Clear existing tabs
            tabStripElement.innerHTML = '';

            tabs.forEach(tab => {
                const tabDiv = document.createElement('div');
                tabDiv.className = 'tab';
                if (tab.id === activeTabId) {
                    tabDiv.classList.add('active');
                }

                tabDiv.innerHTML = `
                    ${tab.title}
                    <span class="tab-close" data-tab-id="${tab.id}">×</span>
                `;

                // Click to activate
                tabDiv.addEventListener('click', (e) => {
                    if (!e.target.classList.contains('tab-close')) {
                        activeTabId = tab.id;
                        renderTabs();
                        loadActiveTabContent();
                    }
                });

                // Close button click
                const closeBtn = tabDiv.querySelector('.tab-close');
                closeBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    closeTab(tab.id);
                });

                tabStripElement.appendChild(tabDiv);
            });
        }

        function loadActiveTabContent() {
            if (activeTabId && tabs.length > 0) {
                const activeTab = tabs.find(t => t.id === activeTabId);
                if (activeTab) {
                    editorElement.value = activeTab.content;
                }
            } else {
                editorElement.value = '';
            }
        }

        function closeTab(tabId) {
            // Find the tab index
            const tabIndex = tabs.findIndex(t => t.id === tabId);

            if (tabIndex !== -1) {
                // Remove the tab
                tabs.splice(tabIndex, 1);

                // If we're closing the active tab, switch to another one
                if (activeTabId === tabId && tabs.length > 0) {
                    activeTabId = tabs[Math.min(tabIndex, tabs.length - 1)].id;
                } else if (tabs.length === 0) {
                    activeTabId = null;
                }

                renderTabs();
                loadActiveTabContent();
                saveNotepadState();
            }
        }

        function updateActiveTabContent() {
            if (activeTabId) {
                const tab = tabs.find(t => t.id === activeTabId);
                if (tab) {
                    tab.content = editorElement.value;
                    saveNotepadState();
                }
            }
        }

        // Save and load notepad state from localStorage
        function saveNotepadState() {
            const state = {
                tabs: tabs,
                activeTabId: activeTabId
            };
            localStorage.setItem('notepadState', JSON.stringify(state));
        }

        function loadNotepadState() {
            const savedState = localStorage.getItem('notepadState');

            if (savedState) {
                try {
                    const state = JSON.parse(savedState);
                    tabs = state.tabs || [];
                    activeTabId = state.activeTabId;

                    // If no active tab but we have tabs, set the first one as active
                    if (tabs.length > 0 && !activeTabId) {
                        activeTabId = tabs[0].id;
                    }
                } catch (e) {
                    console.error('Error loading notepad state:', e);
                    // Reset to default state on error
                    tabs = [];
                    activeTabId = null;
                }
            }

            renderTabs();
            loadActiveTabContent();
        }

        // Notepad event listeners
        newTabButton.addEventListener('click', createNewTab);

        editorElement.addEventListener('input', updateActiveTabContent);

        // Window management
        function openWindow(windowId) {
            // Hide all windows first
            document.querySelectorAll('.window').forEach(win => win.classList.remove('active'));

            // Show the requested window
            const targetWindow = document.getElementById(windowId);
            if (targetWindow) {
                targetWindow.classList.add('active');

                // If it's the files window and not initialized, initialize it
                if (windowId === 'files-window' && currentPath === '/') {
                    renderFiles();
                }

                // If it's the notepad window and tabs haven't been loaded, load them
                if (windowId === 'notepad-window' && tabs.length === 0) {
                    loadNotepadState();
                }
            }
        }

        function closeWindow(windowId) {
            document.getElementById(windowId).classList.remove('active');
        }

        // Add close button functionality to all windows
        document.querySelectorAll('.win-close').forEach(closeBtn => {
            closeBtn.addEventListener('click', (e) => {
                const window = e.target.closest('.window');
                if (window) {
                    closeWindow(window.id);
                }
            });
        });

        // Launcher event listeners
        document.getElementById('open-files').addEventListener('click', () => openWindow('files-window'));
        document.getElementById('open-notepad').addEventListener('click', () => openWindow('notepad-window'));

        // Initialize files window on load
        renderFiles();

        // Load notepad state if available
        loadNotepadState();
    </script>
</body>
</html>
